import{_ as e,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Placas de identificación de motores","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-equipment/motors/motor-nameplates.md","filePath":"es/industrial-equipment/motors/motor-nameplates.md"}'),c={name:"es/industrial-equipment/motors/motor-nameplates.md"};function n(l,a,s,t,d,p){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="placas-de-identificacion-de-motores" tabindex="-1">Placas de identificación de motores <a class="header-anchor" href="#placas-de-identificacion-de-motores" aria-label="Permalink to &quot;Placas de identificación de motores&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las placas de identificación de motores proporcionan información técnica esencial sobre las características eléctricas y mecánicas de un motor.</p><p>Contienen datos estandarizados requeridos para instalación, operación, protección y mantenimiento.</p><p>Comprender la información de la placa es crítico para seleccionar, conectar y operar motores correctamente.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de las placas de identificación de motores es:</p><ul><li>Definir los límites de operación del motor</li><li>Proporcionar datos eléctricos y de desempeño clave</li><li>Asegurar instalación y conexión adecuadas</li><li>Soportar la selección correcta de dispositivos de protección y control</li></ul><p>Las placas actúan como la referencia principal para las especificaciones del motor.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La placa se adhiere a la carcasa del motor e incluye valores nominales determinados por el fabricante.</p><p>Estos valores definen las condiciones bajo las cuales el motor está diseñado para operar de forma segura y eficiente.</p><p>La información común incluye:</p><ul><li>Voltaje y frecuencia nominales</li><li>Corriente a plena carga</li><li>Potencia nominal</li><li>Velocidad</li><li>Factor de potencia y eficiencia</li><li>Clase de aislamiento y límites de temperatura</li></ul><p>Estos datos se utilizan para configurar el sistema eléctrico y verificar compatibilidad con la aplicación.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las placas de identificación de motores se utilizan en:</p><ul><li>Instalación y puesta en marcha de motores</li><li>Selección de cables, interruptores y dispositivos de protección</li><li>Configuración de variadores y sistemas de control</li><li>Mantenimiento y resolución de problemas</li><li>Verificación del desempeño del motor</li></ul><p>Son esenciales a lo largo del ciclo de vida del motor.</p><h2 id="parametros-clave" tabindex="-1">Parámetros clave <a class="header-anchor" href="#parametros-clave" aria-label="Permalink to &quot;Parámetros clave&quot;">​</a></h2><ul><li><p><strong>Voltaje y frecuencia</strong><br> Deben coincidir con el suministro de potencia</p></li><li><p><strong>Corriente nominal</strong><br> Se utiliza para dimensionar protección y conductores</p></li><li><p><strong>Potencia nominal</strong><br> Indica la capacidad de salida mecánica</p></li><li><p><strong>Velocidad</strong><br> Define las características de operación bajo carga</p></li><li><p><strong>Eficiencia</strong><br> Indica el desempeño energético</p></li><li><p><strong>Factor de servicio</strong><br> Define la capacidad de sobrecarga permitida bajo condiciones específicas</p></li><li><p><strong>Clase de aislamiento</strong><br> Determina los límites térmicos y la durabilidad</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Siempre verificar los datos de la placa antes de conectar un motor</li><li>Voltaje o frecuencia incorrectos pueden causar daño inmediato</li><li>Los dispositivos de protección deben configurarse según la corriente de la placa</li><li>El factor de servicio no debe utilizarse para operación continua en sobrecarga</li><li>Los datos de la placa representan condiciones nominales, no todos los escenarios de operación posibles</li></ul>',23)])])}const f=e(c,[["render",n]]);export{u as __pageData,f as default};
